
import json
import os
import re
import sys
import sqlglot
import sqlite3
import logging

# Ensure project root is on sys.path so top-level imports like `config` work
sys.path.append(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
from config import settings

logger = logging.getLogger(__name__)

Unsupport_cmd = ["DELETE", "DROP", "UPDATE", "INSERT", "ALTER", "CREATE", "TRUNCATE", "REPLACE"]


class SQLExecutor:
    def __init__(self):
        self.conn = None
        self.cursor = None
        self.schema_data = None

        try:
            if os.path.exists(settings.JSON_FILE_PATH):
                with open(settings.JSON_FILE_PATH, "r", encoding="utf-8") as f:
                    self.schema_data = json.load(f)
        except Exception:
            logger.exception("Failed to load schema metadata from %s", settings.JSON_FILE_PATH)
            self.schema_data = None

        self.schema_map = self._build_schema_map(self.schema_data)

    def _build_schema_map(self,schema_data):
        if not schema_data:
            return {}
        schema_map = {}
        for table in schema_data:
            schema_map[
                table["table_name"]] = set(
                col["column_name"]
                for col in table["columns"]
            )
        return schema_map

    def __enter__(self):
        self.conn = sqlite3.connect(settings.SQL_DB_PATH)
        self.cursor = self.conn.cursor()
        logger.info("Connection established to %s", settings.SQL_DB_PATH)
        return self  

    def __exit__(self, exc_type, exc_val, exc_tb):
        try:
            if self.conn:
                self.cursor.close()
                self.conn.close()
                logger.info("Connection closed automatically")
        except Exception:
            logger.exception("Error closing DB connection")
        return False

    def _extract_tables(self, query):
        tables = []
        matches = re.findall(
            r"(?:FROM|JOIN)\s+([a-zA-Z_][a-zA-Z0-9_]*)",
            query,
            re.IGNORECASE
        )
        for table in matches:
            tables.append(table)
        return list(set(tables))
    
    def _validate_tables(self, query):
        tables = self._extract_tables(query)
        for table in tables:
            if table not in self.schema_map:
                return {
                    "status":"failed",
                    "reason":"INVALID_TABLE",
                    "details":table
                }
        return {
            "status":"success"
        }
    def _extract_columns(self, query):

        select_match = re.search(
            r"SELECT(.*?)FROM",
            query,
            re.IGNORECASE | re.DOTALL
        )
        if not select_match:
            return []
        select_part = select_match.group(1)
        cols = []
        for col in select_part.split(","):
            col = col.strip()
            if "." in col:
                col = col.split(".")[-1]
            if " AS " in col.upper():
                col = col.split()[0]
            cols.append(col)
        return cols

    def _validate_columns(self, query):

        columns = self._extract_columns(query)
        valid_columns = set()
        for cols in self.schema_map.values():
            valid_columns.update(cols)
        for col in columns:
            if col == "*":
                continue
            if "(" in col:
                continue

            if col not in valid_columns:
                return {
                    "status":"failed",
                    "reason":"INVALID_COLUMN",
                    "details":col
                }
        return {
            "status":"success"
        }

    def _validator(self,query):
        query_upper = query.upper().strip()
        
        unsupport_check = any(cmd in query_upper for cmd in Unsupport_cmd)
        if unsupport_check:
            return {
                "status":"failed",
                "reason":"UNSUPPORTED_OPERATION",
                "details":" ".join(Unsupport_cmd) +" being used"
            }
        
        try:
            sql_instance = sqlglot.parse_one(query,read="sqlite")
            logger.info("Query sucessfully executed")
            if not isinstance(sql_instance,(sqlglot.exp.Select,sqlglot.exp.Subquery)):
                return {
                    "status":"failed",
                    "reason":"Dangerous execution node found",
                    "details":"please review query some modify code block has been observed"
                }    
        except Exception as e:
            return {
                "status":"failed",
                "reason":"Exception while using SQL validator",
                "details":f"Exception is {e}"
            }
        
        table_check = self._validate_tables(query)
        if table_check["status"] == "failed":
            logger.warning("Table validation failed: %s", table_check)
            return table_check
        # print(f"validating column_check and table_check results {table_check}")
        column_check = self._validate_columns(query)
        if column_check["status"] == "failed":
            logger.warning("Column validation failed: %s", column_check)
            return column_check
        # print(f"validated column_check results {column_check}")
        return {
                "status":"success",
                "reason":"Success"
            }
    
    def execute_query(self,query):

        clean_query = " ".join(query.split())
        
        # validation_check = self._validator(clean_query)
        # # print("validation_check", validation_check)
        # if validation_check["status"] == "failed":
        #     return validation_check
        # print ("executing the query")
        if not clean_query.upper().startswith(("SELECT", "WITH")):
            logger.error("Rejected non-SELECT query: %s", clean_query[:200])
            raise Exception("query not started with SELECT or WITH")

        try:
            self.cursor.execute(clean_query)
            columns = self._get_columns()
            table_data = self.cursor.fetchall()
        except Exception:
            logger.exception("Failed executing query: %s", clean_query)
            raise

        if not table_data:
            logger.info("Query returned no rows")
            return []

        logger.info("table_data fetched; rows=%s", len(table_data))
        table_data = table_data[:settings.MAX_ROWS]
        final_data = self._format_result(columns, table_data)
        logger.info("table_data results formatted; rows=%s", len(final_data))
        return final_data
    
    def _get_columns(self):
        cols = self.cursor.description
        
        col_data = [col[0] for col in cols]
        return  col_data
    
    def _format_result(self,columns,table_data):
        final_data = []
        for row in table_data:
            final_data.append(
                dict(zip(columns,row)))
        return final_data
    


